// Generated by Claude Opus 4.6

import { BackupStatus } from '@eclipse-che/common';
import React from 'react';

import { BackupStatusBadge, Props } from '@/components/BackupStatusBadge';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

jest.mock('@/services/helpers/dates', () => ({
  formatDate: jest.fn(() => `Jan 15, 2:30 pm`),
  formatRelativeDate: jest.fn(() => '2 hours ago'),
}));

const { createSnapshot, renderComponent } = getComponentRenderer(getComponent);

function getComponent(props: Props): React.ReactElement {
  return <BackupStatusBadge {...props} />;
}

describe('BackupStatusBadge', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('snapshots', () => {
    test('success status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.SUCCESS,
        lastBackupTime: '2025-01-15T14:30:00Z',
      });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });

    test('failed status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.FAILED,
        lastBackupTime: '2025-01-15T14:30:00Z',
      });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });

    test('in-progress status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.IN_PROGRESS,
      });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });

    test('never status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.NEVER,
      });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('status labels', () => {
    test('should display "Success" for success status', () => {
      renderComponent({
        status: BackupStatus.SUCCESS,
      });

      const badge = screen.getByTestId('backup-status-badge');
      expect(badge).toHaveTextContent('Success');
    });

    test('should display "Failed" for failed status', () => {
      renderComponent({
        status: BackupStatus.FAILED,
      });

      const badge = screen.getByTestId('backup-status-badge');
      expect(badge).toHaveTextContent('Failed');
    });

    test('should display "In Progress" for in-progress status', () => {
      renderComponent({
        status: BackupStatus.IN_PROGRESS,
      });

      const badge = screen.getByTestId('backup-status-badge');
      expect(badge).toHaveTextContent('In Progress');
    });

    test('should display "Never" for never status', () => {
      renderComponent({
        status: BackupStatus.NEVER,
      });

      const badge = screen.getByTestId('backup-status-badge');
      expect(badge).toHaveTextContent('Never');
    });
  });

  describe('tooltip content', () => {
    test('should include status in tooltip', () => {
      renderComponent({
        status: BackupStatus.SUCCESS,
      });

      const tooltip = screen.getByTestId('backup-status-tooltip-content');
      expect(tooltip).toHaveTextContent('Status: Success');
    });

    test('should include formatted date in tooltip when lastBackupTime is provided', () => {
      renderComponent({
        status: BackupStatus.SUCCESS,
        lastBackupTime: '2025-01-15T14:30:00Z',
      });

      const tooltip = screen.getByTestId('backup-status-tooltip-content');
      expect(tooltip).toHaveTextContent('Last backup: Jan 15, 2:30 pm');
    });

    test('should include image URL in tooltip when backupImageUrl is provided', () => {
      renderComponent({
        status: BackupStatus.SUCCESS,
        lastBackupTime: '2025-01-15T14:30:00Z',
        backupImageUrl: 'image-registry.svc:5000/namespace/workspace:latest',
      });

      const tooltip = screen.getByTestId('backup-status-tooltip-content');
      expect(tooltip).toHaveTextContent(
        'Image: image-registry.svc:5000/namespace/workspace:latest',
      );
    });

    test('should include never-backed-up message for never status', () => {
      renderComponent({
        status: BackupStatus.NEVER,
      });

      const tooltip = screen.getByTestId('backup-status-tooltip-content');
      expect(tooltip).toHaveTextContent('This workspace has never been backed up.');
    });

    test('should not include never-backed-up message for other statuses', () => {
      renderComponent({
        status: BackupStatus.SUCCESS,
      });

      const tooltip = screen.getByTestId('backup-status-tooltip-content');
      expect(tooltip).not.toHaveTextContent('never been backed up');
    });
  });

  describe('icon rendering', () => {
    test('should render CheckCircleIcon for success status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.SUCCESS,
      });
      const tree = snapshot.toJSON();
      expect(tree).toMatchSnapshot();
    });

    test('should render animated InProgressIcon for in-progress status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.IN_PROGRESS,
      });
      const tree = snapshot.toJSON();
      expect(tree).toMatchSnapshot();
    });

    test('should render ExclamationTriangleIcon for failed status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.FAILED,
      });
      const tree = snapshot.toJSON();
      expect(tree).toMatchSnapshot();
    });

    test('should render InfoCircleIcon for never status', () => {
      const snapshot = createSnapshot({
        status: BackupStatus.NEVER,
      });
      const tree = snapshot.toJSON();
      expect(tree).toMatchSnapshot();
    });
  });
});
